Module[{b3, chiEff, nGenCanonical, nGenShortcut},
  b3 = 24;
  chiEff = 144;
  (* Canonical formula: Atiyah-Singer index theorem for G2 compactification *)
  (* n_gen = chi_eff / 48, where 48 = spinor_dim * topological_normalization *)
  nGenCanonical = chiEff / 48;
  (* Equivalent shortcut: b3/8 (since chi_eff = 6*b3 for TCS #187) *)
  nGenShortcut = b3 / 8;
  (* Both must equal 3 and agree *)
  {nGenCanonical, nGenShortcut, nGenCanonical == 3, nGenCanonical == nGenShortcut}
]
